import{_ as o}from"./chunks/dashboard_01.InoLIzPU.js";import{_ as a,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"ru/getting-started/dashboard.md","filePath":"ru/getting-started/dashboard.md"}'),s={name:"ru/getting-started/dashboard.md"};function n(l,e,c,d,h,g){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="dashboard" tabindex="-1"><i class="ph ph-speedometer"></i> Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-speedometer&quot;&gt;&lt;/i&gt; Dashboard&quot;">​</a></h1><p><strong>Dashboard</strong> — это мощный In-game профайлер и панель управления. Он позволяет отслеживать работу плагина, анализировать тайминги кадров и вручную переключать уровни скейлеров прямо в запущенном билде.</p><p><img src="'+o+'" alt=""></p><h2 id="как-использовать" tabindex="-1">Как использовать <a class="header-anchor" href="#как-использовать" aria-label="Permalink to &quot;Как использовать&quot;">​</a></h2><p>Просто перетащите префаб <code>Dashboard.prefab</code> на любую сцену вашего проекта.<br> Он автоматически сделает себя <code>DontDestroyOnLoad</code> и будет доступен при переходах между сценами.</p><div class="info custom-block"><p class="custom-block-title">Примечание для релизных сборок (Production Builds)</p><p>Dashboard полностью отделен от ядра плагина. Перед публикацией игры просто удалите префаб со сцены. Система Code Stripping в Unity автоматически вырежет весь код дашборда из финального билда (избегая засорения через папку <code>Resources</code>), сохранив минимальный вес проекта. Само ядро WebAP продолжит работать в фоне.</p></div><h2 id="левая-панель-управление" tabindex="-1"><i class="ph ph-sliders"></i> Левая панель (Управление) <a class="header-anchor" href="#левая-панель-управление" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; Левая панель (Управление)&quot;">​</a></h2><p>Левая часть Дашборда предназначена для взаимодействия с плагином в реальном времени.</p><ul><li><strong>Enable Web AP</strong><br> Глобальный переключатель работы ядра плагина. Если выключить, автоматическая оптимизация остановится, а все параметры графики вернутся к исходным (максимальным) значениям.</li><li><strong>Anti Yo-Yo Protection</strong><br> Включает или отключает систему штрафов. Если выключить, плагин сможет повышать и понижать графику без временных блокировок.<br><em>(См. подробнее: <a href="./../advanced/anti-yoyo">Anti Yo-Yo System</a>)</em></li><li><strong>Active Scalers</strong><br> Список всех модулей оптимизации, добавленных в систему. <ul><li><strong>Переключатель (Toggle):</strong> Позволяет динамически включить или полностью отключить конкретный скейлер.</li><li><strong>Ползунок (Slider):</strong> Ручное переопределение уровня качества (<code>Override Level</code>). Значение <code>0</code> — максимальное качество. Если потянуть ползунок, Индексатор перестанет управлять этим скейлером, и вы сможете визуально оценить его влияние на игру.</li><li><strong>Resolution Mode:</strong> Эксклюзивная настройка для <code>Resolution Scaler</code> (в режиме BiRP). Позволяет на лету переключаться между стратегиями масштабирования <code>NativeBrowserScaling</code> и <code>RenderTextureScaling</code>.<br><em>(См. подробнее: <a href="./../scalers/reference">Справочник скейлеров (Scalers Reference)</a>)</em></li></ul></li></ul><h2 id="правая-панель-аналитика" tabindex="-1"><i class="ph ph-chart-bar"></i> Правая панель (Аналитика) <a class="header-anchor" href="#правая-панель-аналитика" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-bar&quot;&gt;&lt;/i&gt; Правая панель (Аналитика)&quot;">​</a></h2><p>Правая часть показывает сырые метрики движка и внутреннюю логику &quot;мозга&quot; плагина. Для сглаживания графиков используется Zero-GC алгоритм экспоненциального скользящего среднего.</p><h3 id="metrics-timings" tabindex="-1">Metrics &amp; Timings <a class="header-anchor" href="#metrics-timings" aria-label="Permalink to &quot;Metrics &amp; Timings&quot;">​</a></h3><ul><li><strong>Target Min FPS:</strong> Базовая линия производительности, взятая из ваших Project Settings.</li><li><strong>Current FPS:</strong> Текущая частота кадров с историческим графиком спайков.</li><li><strong>Current Scale / DPI:</strong> Текущий множитель разрешения. <code>1.00</code> означает нативное разрешение. Значения ниже (например, <code>0.50</code>) означают, что разрешение 3D-мира снижено для экономии GPU.</li><li><strong>Frame Time / CPU Time:</strong> Точные аппаратные тайминги, собранные через <code>FrameTimingManager</code>. Помогают понять, сколько реального времени процессор тратит на логику кадра.</li></ul><h3 id="plugin-brain" tabindex="-1">Plugin Brain <a class="header-anchor" href="#plugin-brain" aria-label="Permalink to &quot;Plugin Brain&quot;">​</a></h3><p>Здесь отображается логика конвейера принятия решений.<br><em>(См. подробнее: <a href="./../advanced/how-it-works">Архитектура (How it Works)</a>)</em></p><ul><li><strong>Bottleneck:</strong> Какая подсистема устройства сейчас тормозит (<code>CPU</code>, <code>GPU</code>, <code>TargetFrameRate</code> или <code>Unknown</code>).</li><li><strong>Action:</strong> Что Индексатор собирается сделать (<code>IncreaseQuality</code>, <code>DecreaseQuality</code> или <code>Stale</code> — если ничего делать не нужно).</li><li><strong>Status (под Action):</strong> Состояние системы: <code>Monitoring...</code> (оценка кадра), <code>Cooldown</code> (ожидание стабилизации после изменения графики) или <code>Penalty Lockout</code> (сработал штраф Anti Yo-Yo).</li></ul><h3 id="active" tabindex="-1">Active <a class="header-anchor" href="#active" aria-label="Permalink to &quot;Active&quot;">​</a></h3><ul><li>Список скейлеров, уровень которых прямо сейчас <strong>снижен</strong> системой для экономии производительности. Если FPS высокий и всё отлично, здесь будет отображаться <code>- None</code>.</li></ul>',18)])])}const b=a(s,[["render",n]]);export{m as __pageData,b as default};
